--
-- Table structure for table `tbl_admission`
--

DROP TABLE IF EXISTS `tbl_admission`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_admission` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `patient_id` int(11) NOT NULL,
  `bed_id` int(11) DEFAULT NULL,
  `admitted_at` datetime NOT NULL,
  `discharged_at` datetime DEFAULT NULL,
  `admission_status` varchar(32) NOT NULL DEFAULT 'admitted',
  `admitting_diagnosis` varchar(512) DEFAULT NULL,
  `discharge_summary` text DEFAULT NULL,
  `admitted_from` varchar(32) DEFAULT 'walk_in',
  `opd_visit_id` int(11) DEFAULT NULL,
  `facility_admission_id` int(11) DEFAULT NULL,
  `admitting_department` varchar(120) DEFAULT NULL COMMENT 'Clinical department responsible for the inpatient stay',
  `consultation_id` int(11) DEFAULT NULL COMMENT 'Consultation where inpatient stay was ordered',
  `primary_nurse_id` int(11) DEFAULT NULL COMMENT 'Assigned ward nurse (tbl_employee.id, typically role 7)',
  `clinically_discharged_at` datetime DEFAULT NULL COMMENT 'When the doctor authorized clinical discharge',
  `clinical_discharge_by` int(11) DEFAULT NULL COMMENT 'Doctor (tbl_employee.id) who authorized discharge',
  `clinical_discharge_notes` text DEFAULT NULL COMMENT 'Reason/notes for clinical discharge',
  `admitting_doctor_id` int(11) DEFAULT NULL,
  `deposit_amount` decimal(12,2) DEFAULT 0.00,
  `running_bill` decimal(12,2) DEFAULT 0.00,
  `ipd_status` varchar(30) DEFAULT 'admitted',
  `clinical_discharged_at` datetime DEFAULT NULL,
  `clinical_discharged_by` int(11) DEFAULT NULL,
  `financial_discharged_at` datetime DEFAULT NULL,
  `financial_discharged_by` int(11) DEFAULT NULL,
  `follow_up_instructions` text DEFAULT NULL,
  `final_payment_amount` decimal(12,2) DEFAULT NULL,
  `final_payment_method` varchar(60) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `ipd_payment_code` varchar(40) DEFAULT NULL,
  `ipd_paid_at` datetime DEFAULT NULL,
  `follow_up` text DEFAULT NULL,
  `ipd_refund_amount` decimal(12,2) DEFAULT 0.00,
  `ipd_refund_method` varchar(20) DEFAULT NULL,
  `ipd_refunded_at` datetime DEFAULT NULL,
  `ipd_payment_code_generated_at` datetime DEFAULT NULL,
  `ipd_code_consumed_at` datetime DEFAULT NULL,
  `ipd_code_service_label` varchar(120) DEFAULT NULL,
  `relative_name` varchar(120) DEFAULT NULL,
  `relative_phone` varchar(60) DEFAULT NULL,
  `relative_relation` varchar(60) DEFAULT NULL,
  `hospitalization_reason` varchar(500) DEFAULT NULL,
  `primary_surgeon_id` int(11) DEFAULT NULL,
  `care_plan_template_id` int(11) DEFAULT NULL,
  `legal_case_notes` text DEFAULT NULL,
  `discharge_outcome` enum('normal','transferred','deceased','ama') DEFAULT NULL,
  PRIMARY KEY (`id`),
