CREATE TABLE `tbl_charge` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `patient_id` int(11) NOT NULL,
  `cpt_code` varchar(16) DEFAULT NULL,
  `description` varchar(512) NOT NULL,
  `amount` decimal(12,2) NOT NULL DEFAULT 0.00,
  `posted_at` datetime NOT NULL,
  `credit_account_id` int(11) DEFAULT NULL,
  `on_credit` tinyint(4) NOT NULL DEFAULT 0 COMMENT '1=posted to patient AR, no immediate receipt',
  PRIMARY KEY (`id`),
  KEY `idx_ch_pat` (`patient_id`),
  KEY `idx_charge_credit_acct` (`credit_account_id`),
  KEY `idx_charge_on_credit` (`facility_id`,`patient_id`,`on_credit`),
  CONSTRAINT `fk_ch_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`),
  CONSTRAINT `fk_ch_pat` FOREIGN KEY (`patient_id`) REFERENCES `tbl_patient` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2144 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
