DROP TABLE IF EXISTS `tbl_credit_account`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_credit_account` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `patient_id` int(11) NOT NULL,
  `status` varchar(24) NOT NULL DEFAULT 'active' COMMENT 'active|closed|collections|written_off',
  `emergency_payment_pending` tinyint(4) NOT NULL DEFAULT 0 COMMENT '1=walk-in / payment pending flag',
  `guarantor_name` varchar(220) DEFAULT NULL,
  `guarantor_phone` varchar(64) DEFAULT NULL,
  `guarantor_relation` varchar(120) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `invoice_due_date` date DEFAULT NULL COMMENT 'Optional target for full payment',
  `opened_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `closed_at` datetime DEFAULT NULL,
  `writeoff_at` datetime DEFAULT NULL,
  `writeoff_approved_by` int(11) DEFAULT NULL,
  `writeoff_note` varchar(600) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_cr_fac_pat` (`facility_id`,`patient_id`),
  KEY `idx_cr_fac_stat` (`facility_id`,`status`),
  KEY `fk_cr_pat` (`patient_id`),
  CONSTRAINT `fk_cr_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`) ON DELETE CASCADE,
