--
-- Table structure for table `tbl_expense`
--

DROP TABLE IF EXISTS `tbl_expense`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_expense` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL DEFAULT 1,
  `expense_date` date NOT NULL,
  `amount_xaf` bigint(20) NOT NULL DEFAULT 0 COMMENT 'Whole XAF',
  `category` varchar(64) NOT NULL DEFAULT 'other' COMMENT 'consumables|pharma|utilities|rent|salaries|external|equipment|other',
  `payee` varchar(180) NOT NULL DEFAULT '',
  `description` varchar(500) NOT NULL DEFAULT '',
  `payment_method` varchar(50) NOT NULL DEFAULT 'Cash',
  `cost_center_id` int(11) DEFAULT NULL,
  `fin_journal_id` int(11) DEFAULT NULL COMMENT 'Posted GL journal',
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_exp_fac_date` (`facility_id`,`expense_date`),
  KEY `idx_exp_journal` (`fin_journal_id`),
  KEY `idx_exp_cc` (`cost_center_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2652 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

