DROP TABLE IF EXISTS `tbl_fin_journal_line`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_fin_journal_line` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `journal_id` int(11) NOT NULL,
  `account_id` int(11) DEFAULT NULL,
  `cost_center_id` int(11) DEFAULT NULL,
  `line_memo` varchar(255) DEFAULT NULL,
  `debit` bigint(20) NOT NULL DEFAULT 0 COMMENT 'XAF whole units',
  `credit` bigint(20) NOT NULL DEFAULT 0 COMMENT 'XAF whole units',
  `account_code` varchar(32) NOT NULL DEFAULT '',
  `account_label` varchar(160) NOT NULL DEFAULT '',
  PRIMARY KEY (`id`),
  KEY `idx_fin_jl_journal` (`journal_id`),
  KEY `idx_fin_jl_account` (`account_id`),
  KEY `idx_fin_jl_cc` (`cost_center_id`),
  CONSTRAINT `fk_fin_jl_cc` FOREIGN KEY (`cost_center_id`) REFERENCES `tbl_fin_cost_center` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_fin_jl_j` FOREIGN KEY (`journal_id`) REFERENCES `tbl_fin_journal_header` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7705 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

