DROP TABLE IF EXISTS `tbl_inventory_item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_inventory_item` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `sku` varchar(64) NOT NULL,
  `name` varchar(250) NOT NULL,
  `category` varchar(64) NOT NULL DEFAULT 'supply',
  `category_id` int(11) DEFAULT NULL,
  `quantity` int(11) NOT NULL DEFAULT 0,
  `reorder_level` int(11) NOT NULL DEFAULT 0,
  `service_catalog_id` int(11) DEFAULT NULL,
  `unit_price` decimal(12,2) DEFAULT 0.00,
  `medicine_type_id` int(11) DEFAULT NULL,
  `medicine_category_id` int(11) DEFAULT NULL,
  `expiry_date` date DEFAULT NULL,
  `manufacturing_company` varchar(255) DEFAULT NULL,
  `requires_prescription` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_inv_sku` (`facility_id`,`sku`),
  KEY `idx_invitem_cat` (`category_id`),
  KEY `idx_invitem_svc` (`service_catalog_id`),
  CONSTRAINT `fk_invitem_cat` FOREIGN KEY (`category_id`) REFERENCES `tbl_inventory_category` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_invitem_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`),
  CONSTRAINT `fk_invitem_svc` FOREIGN KEY (`service_catalog_id`) REFERENCES `tbl_service_catalog` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=325 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
