--
-- Table structure for table `tbl_inventory_stock_movement`
--

DROP TABLE IF EXISTS `tbl_inventory_stock_movement`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_inventory_stock_movement` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `inventory_item_id` int(11) NOT NULL,
  `qty_delta` int(11) NOT NULL COMMENT 'Negative = out, positive = in',
  `quantity_after` int(11) NOT NULL DEFAULT 0,
  `movement_type` varchar(32) NOT NULL DEFAULT 'adjustment' COMMENT 'purchase|adjustment|dispense|return|transfer',
  `note` varchar(255) DEFAULT NULL,
  `ref_table` varchar(48) DEFAULT NULL,
  `ref_id` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL COMMENT 'tbl_employee.id',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_mov_item` (`inventory_item_id`,`created_at`),
  KEY `idx_mov_fac` (`facility_id`,`created_at`),
  CONSTRAINT `fk_mov_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_mov_item` FOREIGN KEY (`inventory_item_id`) REFERENCES `tbl_inventory_item` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=328 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

