--
-- Table structure for table `tbl_lab_result`
--

DROP TABLE IF EXISTS `tbl_lab_result`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_lab_result` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `patient_id` int(11) NOT NULL,
  `payment_ticket_code` varchar(32) DEFAULT NULL,
  `payment_ticket_line` smallint(5) unsigned DEFAULT NULL,
  `referred_by_id` int(11) DEFAULT NULL COMMENT 'Ordering / referring clinician (tbl_employee)',
  `test_name` varchar(255) NOT NULL,
  `appointment_date` date NOT NULL,
  `status` varchar(32) NOT NULL DEFAULT 'pending' COMMENT 'pending | in_progress | received',
  `notes` text DEFAULT NULL,
  `result_template_json` mediumtext DEFAULT NULL,
  `conclusion_code` varchar(32) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `opd_order_item_id` int(11) DEFAULT NULL,
  `source` varchar(20) DEFAULT NULL,
  `external_doc_id` int(11) DEFAULT NULL,
  `structured_result` longtext DEFAULT NULL,
  `template_test_id` varchar(80) DEFAULT NULL,
  `revision_pending` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_lab_res_fac_date` (`facility_id`,`appointment_date`),
  KEY `idx_lab_res_fac_status` (`facility_id`,`status`),
  KEY `idx_lab_res_patient` (`patient_id`),
  KEY `fk_lab_res_ref` (`referred_by_id`),
  KEY `idx_lab_ticket` (`facility_id`,`payment_ticket_code`,`payment_ticket_line`),
  CONSTRAINT `fk_lab_res_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`),
  CONSTRAINT `fk_lab_res_patient` FOREIGN KEY (`patient_id`) REFERENCES `tbl_patient` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_lab_res_ref` FOREIGN KEY (`referred_by_id`) REFERENCES `tbl_employee` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=353 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

