--
-- Table structure for table `tbl_opd_visit`
--

DROP TABLE IF EXISTS `tbl_opd_visit`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_opd_visit` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL,
  `patient_id` int(11) NOT NULL,
  `ticket_number` varchar(40) NOT NULL,
  `queue_status` varchar(40) NOT NULL DEFAULT 'registered',
  `chief_complaint` varchar(512) DEFAULT NULL,
  `department` varchar(120) DEFAULT NULL,
  `priority` varchar(16) NOT NULL DEFAULT 'normal',
  `visit_date` date NOT NULL,
  `queue_started_at` datetime NOT NULL,
  `completed_at` datetime DEFAULT NULL,
  `cancelled_reason` varchar(255) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `assigned_doctor_id` int(11) DEFAULT NULL,
  `treatment_note` varchar(255) DEFAULT NULL,
  `payment_mode` varchar(64) DEFAULT NULL,
  `facility_admission_id` int(11) DEFAULT NULL,
  `payment_code` varchar(100) DEFAULT NULL,
  `is_emergency` tinyint(1) NOT NULL DEFAULT 0,
  `billing_exception_note` varchar(600) DEFAULT NULL,
  `waiver_reason` varchar(255) DEFAULT NULL,
  `triage_notes` text DEFAULT NULL,
  `triage_done_by` int(11) DEFAULT NULL,
  `triage_done_at` datetime DEFAULT NULL,
  `emg_credit_total` decimal(12,2) DEFAULT 0.00,
  `arrival_mode` varchar(40) DEFAULT NULL,
  `referral_source` varchar(160) DEFAULT NULL,
  `acuity_level` tinyint(1) DEFAULT NULL,
  `mlc_flag` tinyint(1) NOT NULL DEFAULT 0,
  `lwbs` tinyint(1) NOT NULL DEFAULT 0,
  `doctor_first_seen` datetime DEFAULT NULL,
  `disposition_at` datetime DEFAULT NULL,
  `er_bed_id` int(11) DEFAULT NULL,
  `consultation_room_id` int(11) DEFAULT NULL,
  `transferred_to_room_at` datetime DEFAULT NULL,
  `carried_forward_from` date DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_opd_ticket` (`facility_id`,`ticket_number`),
  KEY `idx_opd_fac_date` (`facility_id`,`visit_date`),
  KEY `idx_opd_status` (`facility_id`,`queue_status`),
  KEY `fk_opd_pat` (`patient_id`),
  KEY `idx_opd_fa` (`facility_admission_id`),
  CONSTRAINT `fk_opd_fac` FOREIGN KEY (`facility_id`) REFERENCES `tbl_facility` (`id`),
  CONSTRAINT `fk_opd_pat` FOREIGN KEY (`patient_id`) REFERENCES `tbl_patient` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=413 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

