CREATE TABLE `tbl_patient` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `first_name` varchar(250) NOT NULL,
  `last_name` varchar(250) NOT NULL,
  `email` varchar(250) NOT NULL,
  `dob` varchar(250) NOT NULL,
  `gender` varchar(10) NOT NULL,
  `patient_type` varchar(50) NOT NULL,
  `address` text DEFAULT NULL,
  `phone` varchar(32) NOT NULL,
  `status` tinyint(4) NOT NULL COMMENT '1=Active, 0=Inactive',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `facility_id` int(11) NOT NULL DEFAULT 1,
  `portal_password_hash` varchar(255) DEFAULT NULL COMMENT 'bcrypt hash for patient portal',
  `portal_enabled` tinyint(1) NOT NULL DEFAULT 0 COMMENT '1=patient may sign in to portal',
  `cni_number` varchar(50) DEFAULT NULL,
  `emergency_contact_name` varchar(250) DEFAULT NULL,
  `emergency_contact_phone` varchar(50) DEFAULT NULL,
  `cni_issue_date` varchar(50) DEFAULT NULL,
  `next_of_kin_name` varchar(255) DEFAULT NULL,
  `next_of_kin_phone` varchar(50) DEFAULT NULL,
  `next_of_kin_relationship` varchar(100) DEFAULT NULL,
  `age_years` smallint(5) unsigned DEFAULT NULL,
  `age_only_registration` tinyint(1) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_patient_fac` (`facility_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1473 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
