DROP TABLE IF EXISTS `tbl_transaction`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_transaction` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `facility_id` int(11) NOT NULL DEFAULT 1,
  `patient_id` int(11) NOT NULL,
  `description` varchar(500) NOT NULL DEFAULT '',
  `amount` decimal(15,2) NOT NULL DEFAULT 0.00,
  `payment_method` varchar(50) NOT NULL DEFAULT 'Cash',
  `status` varchar(20) NOT NULL DEFAULT 'pending',
  `transaction_date` date NOT NULL,
  `charge_id` int(10) unsigned DEFAULT NULL,
  `appointment_id` int(11) DEFAULT NULL,
  `billing_document_id` int(10) unsigned DEFAULT NULL COMMENT 'Issued receipt id (tbl_billing_document.id)',
  `created_by` int(11) NOT NULL DEFAULT 0,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT NULL ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_txn_billing_document` (`billing_document_id`),
  KEY `idx_txn_facility` (`facility_id`),
  KEY `idx_txn_patient` (`patient_id`),
  KEY `idx_txn_date` (`transaction_date`),
  KEY `idx_txn_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=2059 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

